head.script:
/*
팝업 화면 개발 담당자 없음
/to/in/bulk/tmlbulk/in_201_02_10p   //화종,품목,품명
/to/in/bulk/tmlbulk/in_201_02_04p	//벌크사전정보검색
/to/in/bulk/tmlbulk/in_201_02_15p   //양수양도등록  -> 호출로직은 구현되어 있으나 해당 그리드에 bulkTakingOverClntNo,bulkHandOverClntNo 존재치않음

undefined -> 0으로 하드코딩. 이걸 이렇게 하는게 이해는 안가는데 asis 현 화면이 그렇게 되있음
//ds_List4.setCellData(row4, "fulvehclWt", ds_List3.getCellData(ds_List3.getRowPosition(),"fulvehclWt"));
//ds_List4.setCellData(row4, "mtvehclWt", ds_List3.getCellData(ds_List3.getRowPosition(),"mtvehclWt"));
ds_List4.setCellData(row4, "fulvehclWt", 0);
ds_List4.setCellData(row4, "mtvehclWt", 0);

ozreport 출력 기능 미개발

공통 udc hidden 처리 차후에 해야함

back단에서 에러 발생 -> asis는 아무 얼럿안띄우나 tobe는 공통에서 response 에서 null 에러 메세지 캐치해서 띄움 

개발 안된 팝업 :
in_203_01_04p : 벌크재고관리번호
in_201_02_10p : 화주 팝업
in_201_02_12p : 그리드 작업지시번호 팝업

삭제대상 팝업 : 
in_201_02_15p
-> 작업계획번호 셀 readOnly 및 팝업 X처리
*/
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();;  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)

scwin.g_search_fag = 0;
scwin.submit_flag = "F";

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd: "TB002", compID: "gr_List2:wrkPatternCd" }, // 작업유형
        { grpCd: "TB004", compID: "gr_List2:gaugePatternCd" }, // 측정유형
        { grpCd: "TB005", compID: "lc_wrkShift,gr_List1:wrkShift" }, // 작업시프트
        { grpCd: "TB009", compID: "gr_List2:wrkPlanIndictRelCd" }, // 작업계획지시관계
        { grpCd: "TB012", compID: "gr_List4:wrkRsltsScalCd" }, // 실적계근대
        { grpCd: "TB013", compID: "lc_wrkIndictPrgsStsCd,gr_List1:wrkIndictPrgsStsCd,gr_List3:wrkIndictPrgsStsCd" }, // 작업진행상태
        { grpCd: "TB015", compID: "gr_List4:wrkRsltsRegClsCd" }, // 실적등록구분
        { grpCd: "TB016", compID: "lc_pdaWrkPicNo,gr_List2:pdaWrkPicNo,gr_List4:pdaWrkPicNo" }, // 작업자번호
        { grpCd: "TB022", compID: "gr_List3:wrkVehclWaitPosCd" }, // 차량대기위치
        { grpCd: "TB040", compID: "lc_wrkPlCd" }, // 작업장
        { grpCd: "ZZ210", compID: "gr_List3:tmlEqKndCd" }, // 차량구분
        { grpCd: "SD060", compID: "lc_impExpClsCd" } // 수출입구분
    ]
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

        udc_pubCd.hide();

        scwin.f_SetDefaultData();
        ////임시
        //ica_wrkDt.setValue("20130711");
        ///임시
    }, {"delay":50});
};

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = function () {
    ica_wrkDt.setValue(scwin.vCurDate);
}

scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tb_mainData, null);
    scwin.f_SetDefaultData();
}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () { 
    ds_List1.removeAll();
    ds_List2.removeAll();
    ds_List3.removeAll();
    ds_List4.removeAll();

    dma_condition1.set("wrkDt",          ica_wrkDt.getValue());
    dma_condition1.set("wrkShift",      lc_wrkShift.getValue());
    dma_condition1.set("wrkDtShift",    ica_wrkDt.getValue()+""+lc_wrkShift.getValue());
    dma_condition1.set("impExpClsCd",       lc_impExpClsCd.getValue());
    dma_condition1.set("clntNo",        ed_clntNo.getValue());
    dma_condition1.set("repClntNo",         ed_clntNo.getValue());
    dma_condition1.set("repKcgCd",      lc_repKcgCd.getValue());// 화종 
    dma_condition1.set("commCd",        ed_commCd.getValue());// 품명코드 
    dma_condition1.set("wrkIndictNo",           ed_wrkIndictNo.getValue());// 작업지시번호
    dma_condition1.set("lineCd",        ed_lineCd.getValue());
    dma_condition1.set("blBkNo",        ed_blBkNo.getValue());
    dma_condition1.set("cvsslMgntNo",       ed_cvsslMgntNo.getValue());// 본선관리번호 
    dma_condition1.set("wrkIndictPrgsStsCd",lc_wrkIndictPrgsStsCd.getValue()); // 작업계획진행상태코드 
    dma_condition1.set("pdaWrkPicNo",       lc_pdaWrkPicNo.getValue());// PDA작업담당자번호 
    dma_condition1.set("tmlAdmitckCd",      ed_tmlAdmitckCd.getValue());// 터미널출입증코드 
    dma_condition1.set("clntNoCls",    "1");// 터미널출입증코드   
    dma_condition1.set("wrkPlCd",       lc_wrkPlCd.getValue());// 작업장

    console.log("dma_condition1.getJSON() : ");
    console.log(dma_condition1.getJSON());

    $c.sbm.execute(sbm_queryCondition1);

}


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    var rtnList;  // 공통POP-UP -> 요청화면 
    var pWhere;     // 조회조건             

    switch (disGubun){

        case 1: //화주 팝업 
            udc_clntNo.cfCommonPopUp(
                            scwin.callbackCoopList  // XML상의 SELECT ID  
                            ,pCode                  // 화면에서의 ??? Code Element의  Value
                            ,pName                  // 화면에서의 ??? Name Element의  Value
                            ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                            ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                            ,null                   // Title순서  
                            ,null                   // 보여주는 각 컬럼들의 폭    
                            ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                            ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                            ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                            ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                            ,null                   // 윈도우 위치 Y좌표   
                            ,null                   // 윈도우 위치 X좌표
                            ,null                   // 중복체크여부   ("F")
                            ,'F'                    // 전체검색허용여부 ("F")
                            ,"화주,화주코드,화주명"              // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );
            /*                            
            if (rtnList != null && rtnList[0] != "") {
                ed_clntNo.setValue(rtnList[0]);
                ed_clntNm.setValue(rtnList[1]);
            }
            */
            break;        

        case 2: //화종,품목,품명 팝
        /*
            var win_url = "/to/in/bulk/tmlbulk/in_201_02_10p.jsp?"
                        + "repKcgCd=" + lc_repKcgCd.BindColVal
                        + "&cd="    + em_commCd.text
                        + "&nm="    + txt_commCdNm.value;
            var xwidth  = "500";
            var yheight = "400";
            var xloc = screen.width/2 - xwidth/2;
            var yloc = screen.height/2 - yheight/2;

            var win_style = "left="+xloc+",top="+yloc+",toolbar=no, location=no, directories=no,status=no,menubar=no,scrollbars=no,resizable=no,width="+xwidth+",height="+yheight;

            var win_name = "POPUPWIN";
            var rtnValues = window.showModalDialog(win_url, win_name, win_style);

            if(rtnValues != null){
                if(rtnValues[0]!="N/A"){
                em_commCd.Text=rtnValues[0];
                txt_commCdNm.value=rtnValues[1];    
                lc_repKcgCd.BindColVal=rtnValues[2];    

                }         
            }
        */
            var win_url = "/ui/to/in/bulk/tmlbulk/in_201_02_10p.xml";

            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 750;
            opts.height = 625;
            opts.popupName = '품목 검색';

            var param = {
                repKcgCd : lc_repKcgCd.getValue(),
                cd : ed_commCd.getValue() ,
                nm : ed_commCdNm.getValue()
            }

            rtnList = await $c.win.openPopup(win_url, opts, param);
            console.log("rtnList : " , rtnList);

            if(rtnList != null){
                if(rtnList[0]!=""){
                    ed_commCd.setValue(rtnList[0]);
                    ed_commCdNm.setValue(rtnList[1]);
                    lc_repKcgCd.setValue(rtnList[2]);    
                }         
            }

            break;

        case 3: //LINE 팝업
            udc_lineCd.cfCommonPopUp(
                            scwin.callbackTmlLineInfo   // XML상의 SELECT ID  
                            ,pCode                  // 화면에서의 ??? Code Element의  Value
                            ,pName                  // 화면에서의 ??? Name Element의  Value
                            ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                            ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                            ,null                   // Title순서  
                            ,null                   // 보여주는 각 컬럼들의 폭    
                            ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                            ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                            ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                            ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                            ,null                   // 윈도우 위치 Y좌표   
                            ,null                   // 윈도우 위치 X좌표
                            ,null                   // 중복체크여부   ("F")
                            ,'F'                    // 전체검색허용여부 ("F")
                            ,"LINE,LINE코드,LINE명"                // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
                            );
            /*                                        
            if (rtnList != null && rtnList[0] != "") {
                ed_lineCd.setValue(rtnList[0]);
                ed_lineNm.setValue(rtnList[1]);
            }
            */           
            break;

        case 4: //로케이션등록 팝업
        // 호출하지 않음
