            var win_url = "/to/in/bulk/tmlbulk/in_201_02_05p.jsp?menuid=1=";
            var win_style = "dialogWidth:1024px; dialogHeight:768px";
            var win_name = "POPUPWIN";
            var rtnValues = window.showModalDialog(win_url, win_name, win_style);
            break;
        */

        case 5: //BL/BK 팝업
        /*
            var rtnList = window.showModalDialog('/to/in/bulk/tmlbulk/in_201_02_04p.jsp?paramTitle=BL/BK검색팝업'
                                            ,null
                                            ,"dialogWidth:870px; dialogHeight:550px; status:No");
            if (rtnList != null && rtnList[0] != "N/A") {
                eval(pCode + '= rtnList[12];');
            }
        */


            var win_url = "/ui/to/in/bulk/tmlbulk/in_201_02_04p.xml";

            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 1250;
            opts.height = 725;
            opts.popupName = 'BL/BK검색팝업';

            var param = {};

            rtnList = await $c.win.openPopup(win_url, opts, param);
            console.log("rtnList : " , rtnList);

            if(rtnList != null && rtnList[0] != "") {
                ed_blBkNo.setValue(rtnList[12]);
            }

            break;

        case 6: // 본선관리번호검색 팝업
        /*
            var win_url = "/ds/op/wrkplan/stvwrkplan/op_204_01_07p.jsp?paramTitle=본선관리번호검색팝업";
            var win_style = "dialogWidth:885px; dialogHeight:425px";
            var arrParm = new Array(2);
            arrParm[0] = em_cvsslMgntNo.Text;
            arrParm[1] = '';
            var rtnList = window.showModalDialog(win_url, arrParm, win_style);
            if(rtnList != null && rtnList[0] != "N/A") {
                em_cvsslMgntNo.Text = rtnList[0];
            }
        */
            var win_url = "/ui/ds/op/wrkplan/stvwrkplan/op_204_01_07p.xml";

            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 1350;
            opts.height = 625;
            opts.popupName = '본선관리번호검색팝업';

            var param = new Array();
            param[0] = ed_cvsslMgntNo.getValue(); //본선관리번호
            param[1] = ""; //수출입구분코드

            rtnList = await $c.win.openPopup(win_url, opts, param);
            console.log("rtnList : " , rtnList);

            if(rtnList != null && rtnList[0] != "") {
                ed_cvsslMgntNo.setValue(rtnList[0]);
            } else {
                ed_cvsslMgntNo.setValue("");
            }

            break;

