        /*
            var win_url = "/to/in/bulk/tmlbulk/in_201_02_09p.jsp"
            + "?tmlAdmitckCd="+eval(pCode)
            + "&closeTF="+pClose;
            var win_style = "dialogWidth:800px; dialogHeight:520px";
            var win_name = "POPUPWIN";
            var rtnList = window.showModalDialog(win_url, win_name, win_style);
            if(rtnList == null){
                em_tmlAdmitckCd.Text = "";//  "tmlAdmitckCd"); 
                txt_tmlAdmitckNm.value = "";//  "tempBarcdVehclNo");
            }else if(rtnList[0] != "N/A") {
                em_tmlAdmitckCd.Text = rtnList[0];//  "tmlAdmitckCd"); 
                txt_tmlAdmitckNm.value = rtnList[6];//  "tempBarcdVehclNo");                
            }
        */
            var win_url = "/ui/to/in/bulk/tmlbulk/in_201_02_09p.xml";

            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
