                ed_wrkIndictNo.setValue(rtnList[0]);
            } else {
                ed_wrkIndictNo.setValue("");
            }

            break;  


    }
}


//-------------------------------------------------------------------------
// 공통 Grid Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_OpenGridPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnValues;              // 공통POP-UP -> 요청화면 
    scwin.g_search_fag = 0;     //글로벌변수: 화종조회 초기화

    switch (disGubun){          
        case 1:             
            // 벌크사전정보검색 팝업
            /*
            var win_url = "/to/in/bulk/tmlbulk/in_201_02_04p.jsp";
            //+ "repKcgCd=" + lc_repKcgCd.BindColVal
            //+ "&cd="    + em_commCd.text
            //+ "&nm="    + txt_commCdNm.value;
            var xloc = screen.width/2 - xwidth/2;
            var yloc = screen.height/2 - yheight/2;
            var win_style = "dialogWidth:870px; dialogHeight:550px";
            var win_name = "POPUPWIN";
            var rtnValues = window.showModalDialog(win_url, win_name, win_style);
            */

            var win_url = "/ui/to/in/bulk/tmlbulk/in_201_02_04p.xml";

            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 870;
            opts.height = 550;
            opts.popupName = 'BL/BK검색팝업';

            var param = {};

            rtnValues = await $c.win.openPopup(win_url, opts, param);
            console.log("rtnValues : " , rtnValues);

            if(rtnValues != null){// 조회 결과값을 셋팅한다.  
                g_search_fag = 1;

                ds_List1.setCellData(ds_List1.getRowPosition(),"clntNo",rtnValues[1]); // repClntNo  화주 코드
                ds_List1.setCellData(ds_List1.getRowPosition(),"clntNm",rtnValues[2]); //"repClntNm"  화주 이름
                ds_List1.setCellData(ds_List1.getRowPosition(),"commCd",rtnValues[3]); //"repKcgCd"); //화종 코드
                ds_List1.setCellData(ds_List1.getRowPosition(),"commNm",rtnValues[4]); //"commNm"); // 화종 이름
                ds_List1.setCellData(ds_List1.getRowPosition(),"lineCd",rtnValues[11]); //"lineCd"); // 라인
                ds_List1.setCellData(ds_List1.getRowPosition(),"blBkNo",rtnValues[12]); //"blBkNo"); // BL/BK 번호
                ds_List1.setCellData(ds_List1.getRowPosition(),"impExpClsCd",rtnValues[5]); //"impExpClsCd"); // 수출입 코드
                ds_List1.setCellData(ds_List1.getRowPosition(),"wrkPatternCd",rtnValues[6]); //"wrkPatternCd"); // 작업유형 코드
                ds_List1.setCellData(ds_List1.getRowPosition(),"gaugePatternCd",rtnValues[7]); //"gaugePatternCd"); // 측정 유형 코드                  
