scwin.f_List4AddRow = function () {   
    //alert(ds_List3.text);
    //alert(ds_List4.text);
    //새로 추가된 행에 인덱스를 추가 한다
    //List3에서 작업진행상태가 시작인겨우에만 추가가 가능하다.
    //List3에서 수정상태인데 시작으로 하고 추가 할수 있으므로 막아준다

    if(ds_List3.getRowStatus(ds_List3.getRowPosition()) != "R" && ds_List3.getCellData(ds_List3.getRowPosition(),"wrkIndictPrgsStsCd") == "04"){
        $c.win.alert("작업지시별 작업지시차량내역의 작업진행상태를 변경 후  \"저장 \" 하세요");
        return;
    }

    if(ds_List3.getRowStatus(ds_List3.getRowPosition()) == "R" && ds_List3.getCellData(ds_List3.getRowPosition(),"wrkIndictPrgsStsCd") == "04"){

        ds_List4.insertRow();
        ds_List4.setRowPosition(ds_List4.getRowCount());
        var row4 = ds_List4.getRowPosition() - 1;

        ds_List4.setCellData(row4, "modCls", ds_List3.getCellData(ds_List3.getRowPosition(),"modCls"));
        ds_List4.setCellData(row4, "wrkIndictVehclSeq", ds_List3.getCellData(ds_List3.getRowPosition(),"wrkIndictVehclSeq"));
        ds_List4.setCellData(row4, "tmlAdmitckCd", ds_List3.getCellData(ds_List3.getRowPosition(),"tmlAdmitckCd"));
        ds_List4.setCellData(row4, "vehclNo", ds_List3.getCellData(ds_List3.getRowPosition(),"vehclNo"));
        ds_List4.setCellData(row4, "rsltsQty", ds_List3.getCellData(ds_List3.getRowPosition(),"rsltsQty"));

        //ds_List4.setCellData(row4, "fulvehclWt", ds_List3.getCellData(ds_List3.getRowPosition(),"fulvehclWt"));
        //ds_List4.setCellData(row4, "mtvehclWt", ds_List3.getCellData(ds_List3.getRowPosition(),"mtvehclWt"));
        ds_List4.setCellData(row4, "fulvehclWt", 0);
        ds_List4.setCellData(row4, "mtvehclWt", 0);

        ds_List4.setCellData(row4, "rsltsWt", ds_List3.getCellData(ds_List3.getRowPosition(),"rsltsWt"));
        ds_List4.setCellData(row4, "rsltsCbm", ds_List3.getCellData(ds_List3.getRowPosition(),"rsltsCbm"));
        ds_List4.setCellData(row4, "wrkRsltsScalCd", ds_List3.getCellData(ds_List3.getRowPosition(),"wrkRsltsScalCd"));
        ds_List4.setCellData(row4, "pdaWrkPicNo", ds_List3.getCellData(ds_List3.getRowPosition(),"pdaWrkPicNo"));
        ds_List4.setCellData(row4, "delYn", ds_List3.getCellData(ds_List3.getRowPosition(),"delYn"));
        ds_List4.setCellData(row4, "wrkRsltsRegClsCd", "03");
        ds_List4.setCellData(row4, "rsltsDtHhmmss", ds_List3.getCellData(ds_List3.getRowPosition(),"rsltsDtHhmmss"));
        ds_List4.setCellData(row4, "wrkIndictNo" , ds_List3.getCellData(ds_List3.getRowPosition(),"wrkIndictNo"));
    }else{
        $c.win.alert("작업지시별 작업지시차량내역의 작업진행상태가 \"시작\" 인경우에 추가할 수 있습니다.");
    }
}

