scwin.f_List1Save = async function () {
    if(ds_List1.getModifiedIndex().length == 0 ){
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["작업지시 내역"]); // 은(는) 변경사항이 없습니다
    }else{
        var chkAlert = await $c.win.confirm(MSG_CM_CRM_001);
        if(chkAlert == true){ // 저장하시겠습니까?    
            $c.sbm.execute(sbm_SaveList1);
        }   
    }
}

