scwin.gr_List1_onrowindexchange = function (rowIndex, oldRow) {
    if(rowIndex > -1){
        ds_List2.removeAll();
        ds_List3.removeAll();
        ds_List4.removeAll();
        dma_condition2.set("wrkIndictNo" , ds_List1.getCellData(rowIndex,"wrkIndictNo"));
        $c.sbm.execute(sbm_queryCondition2);
    }
};

scwin.gr_List1_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    var colid = ds_List1.getColumnID(columnIndex);
    var cd = ds_List1.getCellData(rowIndex, "wrkIndictPrgsStsCd");

    switch (colid) {
      case "wrkIndictPrgsStsCd" :
        gr_List1.setCellReadOnly(rowIndex, columnIndex, false);
        break;
    }

    if(cd == "05"){
        gr_List1.setCellReadOnly(rowIndex, columnIndex, true);
    }
};

scwin.gr_List3_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    var colid = ds_List1.getColumnID(columnIndex);
    var cd = ds_List3.getCellData(rowIndex, "wrkIndictPrgsStsCd");

    switch (colid) {          
      case "wrkIndictPrgsStsCd" :
        gr_List1.setCellReadOnly(rowIndex, columnIndex, false);
        break;
    }

    if(cd == "05"){
      gr_List1.setCellReadOnly(rowIndex, columnIndex, true);
    }

    //var row = info.newRowIndex;
    if(rowIndex != oldRow) {
        dma_condition3.set("wrkIndictVehclSeq" , ds_List3.getCellData(rowIndex,"wrkIndictVehclSeq"));
        $c.sbm.execute(sbm_queryCondition4);
    }
};

scwin.gr_List4_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    var colid = ds_List1.getColumnID(columnIndex);
    var wrkRsltsRegClsCd = ds_List4.getCellData(rowIndex,"wrkRsltsRegClsCd");

    switch (colid) {
      case "rsltsQty" ://수량
      case "fulvehclWt" ://만차중량
      case "mtvehclWt" ://공차중량
      case "rsltsWt" ://실적중량
      case "rsltsCbm" ://CBM
      case "wrkRsltsScalCd" ://실적계근대
      case "pdaWrkPicNo" ://PDA작업담당자
      case "delYn" ://삭제여부
        gr_List4.setReadOnly(colid,false);
        break;
    }
    if(wrkRsltsRegClsCd == "02"){
      gr_List4.setReadOnly(colid,true);
    }

    /*
    console.log(rowIndex);
    console.log(columnIndex);
    console.log(oldRow);
    */
    if(oldRow != -1 && rowIndex != oldRow) {
        if(ds_List4.getCellData(oldRow,"vehclNo") == "") {
            $c.win.alert("필수입력 에러:차량번호");
            return false;
        }
    }
};

