scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};


scwin.rsltsDtHhFormat = function (time) {
    var length = time.length;
    var rtn = time;

    if(length > 17){
        rtn = time.substring(0,17);
    }
    return rtn;
}
